// ═══════════════════════════════════════════════════════════════════
// Cálculo de bônus de treino (espelha _prepareNpc do actor-document.mjs)
// ═══════════════════════════════════════════════════════════════════

function ndToNumeric(nd) {
  const s = String(nd).trim();
  if (s === "S" || s === "S+") return 20;
  if (s.includes("/")) {
    const [n, d] = s.split("/").map(Number);
    return n / d;
  }
  return parseInt(s) || 1;
}

function trainingBonus(nd) {
  return Math.max(Math.floor(ndToNumeric(nd) / 2), 2);
}

// ═══════════════════════════════════════════════════════════════════
// Lógica de aplicação
// ═══════════════════════════════════════════════════════════════════

const PERICIA_ATRIBUTO = {
  acrobacia: "des", adestramento: "car", atletismo: "for", atuacao: "car",
  cavalgar: "des", conhecimento: "int", cura: "sab", diplomacia: "car",
  enganacao: "car", fortitude: "con", furtividade: "des", guerra: "int",
  iniciativa: "des", intimidacao: "car", intuicao: "sab", investigacao: "int",
  jogatina: "car", ladinagem: "des", luta: "for", misticismo: "int",
  nobreza: "int", oficio: "int", percepcao: "sab", pilotagem: "des",
  pontaria: "des", reflexos: "des", religiao: "sab", sobrevivencia: "sab",
  vontade: "sab",
};

function buildSystem(p) {
  const bonusTreino = trainingBonus(p.nd);

  const system = {
    nd: String(p.nd),
    biografia: {
      nome: p.name,
      tipo: p.tipo || "Monstro",
      tamanho: p.tamanho || "Médio",
      deslocamento: p.deslocamento || 9,
      descricao: (p.descricao || "") + (p.deslocamentoExtra ? `\n\nDeslocamentos: ${p.deslocamentoExtra}` : ""),
      faccao: "",
      moral: "",
    },
    atributos: {
      for: { value: p.atributos.for || 0, bonus: 0, total: p.atributos.for || 0 },
      des: { value: p.atributos.des || 0, bonus: 0, total: p.atributos.des || 0 },
      con: { value: p.atributos.con || 0, bonus: 0, total: p.atributos.con || 0 },
      int: { value: p.atributos.int || 0, bonus: 0, total: p.atributos.int || 0 },
      sab: { value: p.atributos.sab || 0, bonus: 0, total: p.atributos.sab || 0 },
      car: { value: p.atributos.car || 0, bonus: 0, total: p.atributos.car || 0 },
    },
    pv: { value: p.pv || 10, max: p.pv || 10, temp: 0, bonus: 0 },
    pm: { value: p.pm || 0, max: p.pm || 0, bonus: 0 },
    defesa: {
      base: (p.defesa || 10) - (p.atributos.des || 0),
      armadura: 0,
      outros: 0,
      total: p.defesa || 10,
      cd: 10,
    },
    sentidos: p.sentidos || "",
    tesouro: p.tesouro || "Nenhum",
    resistenciasList: p.resistencias || [],
    bonusCD: 0,
    magia: { atributoChave: "int" },
    global: { rolagem: 0, ataque: 0, pericias: 0, resistencias: 0, dano: 0 },
    condicoes: {},
    pericias: {},
  };

  for (const [key, atr] of Object.entries(PERICIA_ATRIBUTO)) {
    const visiveisPorPadrao = ["iniciativa", "percepcao", "fortitude", "reflexos", "vontade", "luta", "pontaria"];
    system.pericias[key] = {
      atributo: atr, treinada: false, bonus: 0, total: 0,
      mostrar: visiveisPorPadrao.includes(key),
    };
  }

  // Fórmula do actor-document.mjs: total = atributo + (treinada ? bonusTreino : 0) + bonus
  // Auto-detecta treinada quando diff >= bonusTreino.
  // Perícias explícitas do livro — sempre treinadas.
  const setSkill = (key, total, atributo, forceTreinada = false) => {
    const mod = p.atributos[atributo] || 0;
    const diff = total - mod;
    const treinada = forceTreinada || diff >= bonusTreino;
    system.pericias[key].bonus = treinada ? (diff - bonusTreino) : diff;
    system.pericias[key].treinada = treinada;
    system.pericias[key].mostrar = true;
  };

  setSkill("iniciativa", p.iniciativa || 0, "des");
  setSkill("percepcao", p.percepcao || 0, "sab");
  setSkill("fortitude", p.fortitude || 0, "con");
  setSkill("reflexos", p.reflexos || 0, "des");
  setSkill("vontade", p.vontade || 0, "sab");

  for (const [key, total] of Object.entries(p.pericias || {})) {
    const atr = PERICIA_ATRIBUTO[key] || "for";
    if (!system.pericias[key]) continue;
    setSkill(key, total, atr, true);
  }

  return system;
}

function buildItems(p, magiasPackDocs) {
  const items = [];

  for (const atk of (p.ataques || [])) {
    items.push({
      name: atk.nome,
      type: "arma",
      img: "icons/svg/claws.svg",
      system: {
        dano: atk.dano || "",
        critico: atk.critico || "20/x2",
        tipo: atk.tipoDano || "",
        alcance: atk.alcance || "",
        grupo: "Natural",
        bonusAtaque: atk.bonusAtaque || 0,
        bonusDano: 0,
        ataqueNatural: true,
        ignoraAtributoDano: true,
        numAtaques: atk.numAtaques || 1,
        penalidadeMultiplos: 0,
        equipada: true,
        descricao: atk.efeitos ? `Efeito: ${atk.efeitos}` : "",
      },
    });
  }

  for (const hab of (p.habilidades || [])) {
    const displayName = hab.acao && hab.acao !== "Passiva"
      ? `${hab.nome} (${hab.acao}${hab.custoPM ? `, ${hab.custoPM} PM` : ""})`
      : hab.nome;
    items.push({
      name: displayName,
      type: "habilidade",
      img: "icons/svg/book.svg",
      system: {
        descricao: hab.descricao || "",
        tipo: hab.acao === "Passiva" ? "passiva" : "ativa",
        fonte: "Statblock",
      },
    });
  }

  const norm = (s) => String(s || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
  for (const mg of (p.magias || [])) {
    let linked = null;
    if (magiasPackDocs) {
      const needle = norm(mg.nome);
      const found = magiasPackDocs.find(d => norm(d.name) === needle);
      if (found) {
        linked = {
          name: found.name,
          type: "magia",
          img: found.img,
          system: foundry.utils.deepClone(found.system),
        };
        if (mg.custoPM) linked.system.custoPM = mg.custoPM;
      }
    }
    if (linked) {
      items.push(linked);
    } else {
      items.push({
        name: mg.nome,
        type: "magia",
        img: "icons/svg/daze.svg",
        system: {
          descricao: mg.descricao || "",
          custoPM: mg.custoPM || 0,
          execucao: mg.acao || "",
          circulo: Math.max(1, Math.ceil((mg.custoPM || 1) / 2)),
          tipo: "arcana",
        },
      });
    }
  }

  // ── Validação final: descarta items com nome vazio (Foundry rejeita) ──
  return items.filter(it => it.name && String(it.name).trim().length > 0);
}

async function importar() {
  const pack = game.packs.get(PACK_NAME);
  if (!pack) {
    ui.notifications.error(`Pack ${PACK_NAME} não encontrado! Verifique system.json e recarregue.`);
    return;
  }

  let magiasPackDocs = null;
  const magiasPack = game.packs.get(MAGIAS_PACK);
  if (magiasPack) {
    ui.notifications.info("Carregando magias do compêndio para linkagem...");
    magiasPackDocs = await magiasPack.getDocuments();
    console.log(`T20 | ${magiasPackDocs.length} magias carregadas do pack.`);
  } else {
    console.warn(`T20 | Pack ${MAGIAS_PACK} não encontrado — magias serão criadas em branco.`);
  }

  await pack.configure({ locked: false });

  const existing = await pack.getDocuments();
  if (existing.length) {
    ui.notifications.info(`Removendo ${existing.length} criaturas antigas...`);
    for (const doc of existing) await doc.delete();
  }

  ui.notifications.info(`Importando ${DATA.length} criaturas...`);

  let ok = 0, fail = 0;
  for (const p of DATA) {
    try {
      const system = buildSystem(p);
      const items = buildItems(p, magiasPackDocs);

      const actorData = {
        name: p.name,
        type: "npc",
        img: "icons/svg/mystery-man.svg",
        system,
        items,
        prototypeToken: {
          name: p.name,
          displayName: 20,
          actorLink: false,
          disposition: -1,
          sight: { enabled: true, range: 18 },
        },
      };

      await Actor.create(actorData, { pack: PACK_NAME });
      ok++;
    } catch (e) {
      console.error(`T20 | Erro em ${p.name}:`, e);
      fail++;
    }
  }

  await pack.configure({ locked: true });
  ui.notifications.info(`✔ ${ok} criaturas importadas. ${fail ? `(${fail} falharam — veja o console)` : ""}`);
}

importar();
